## Security Considerations

### Path Traversal Prevention
```rust
fn validate_path(&self, requested: &str) -> Result<PathBuf, SecurityError> {
    let requested_path = Path::new(requested);

    // Reject absolute paths in request
    if requested_path.is_absolute() {
        return Err(SecurityError::AbsolutePathRejected);
    }

    // Build full path
    let full_path = self.root.join(requested_path);

    // Canonicalize to resolve ../ etc
    let canonical = full_path.canonicalize()
        .map_err(|_| SecurityError::PathResolutionFailed)?;

    // Verify still under root
    if !canonical.starts_with(&self.root) {
        return Err(SecurityError::PathTraversalAttempt);
    }

    Ok(canonical)
}
```

### Symlink Handling
```rust
fn check_symlink(&self, path: &Path) -> Result<(), SecurityError> {
    if path.is_symlink() && !self.follow_symlinks {
        return Err(SecurityError::SymlinkRejected);
    }

    if self.follow_symlinks {
        // Verify symlink target is still under root
        let target = path.read_link()?;
        let resolved = path.parent().unwrap().join(target).canonicalize()?;
        if !resolved.starts_with(&self.root) {
            return Err(SecurityError::SymlinkEscapesRoot);
        }
    }

    Ok(())
}
```

