async fn test_tool_uses_filesystem_resource() {
    let dir = create_test_filesystem();

    let provider = FilesystemProvider::new(dir.path())
        .with_prefix("config")
        .build();

    #[tool]
    async fn load_config(ctx: &McpContext) -> Result<String, ToolError> {
        let config = ctx.read_resource_text("file://config/config.json").await?;
        Ok(format!("Loaded: {}", config))
